use std::fmt::{self, Display};
use std::iter::IntoIterator;

struct MyCustomCollection {
    items: Vec<i32>,
}

impl IntoIterator for MyCustomCollection {
    type Item = i32;
    type IntoIter = std::vec::IntoIter<Self::Item>;

    fn into_iter(self) -> Self::IntoIter {
        self.items.into_iter()
    }
}

impl Display for MyCustomCollection {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "MyCollection({})", self.items.len())
    }
}

fn process_iterable<T>(collection: T) where T: IntoIterator<Item = i32> {
    let mut count = 0;
    for item in collection.into_iter() {
        println!("Processing item: {}", item);
        count += 1;
    }
    println!("Finished processing, total items found: {}", count);
}

fn main() {
    let data = MyCustomCollection {
        items: vec![10, 20, 30],
    };
    process_iterable(data);
}

