use std::iter::IntoIterator;

struct CalculatorData { data: Vec<i32> }

impl IntoIterator for CalculatorData {
    type Item = i32;
    type IntoIter = std::vec::IntoIter<i32>;

    fn into_iter(self) -> Self::IntoIter {
        self.data.into_iter()
    }
}

fn main() {
    let inputs = CalculatorData { data: vec![10, 20, 30, 40] };
    let mut total_sum = 0;

    for item in inputs.into_iter() {
